"use strict";(self.webpackChunkdocs_next=self.webpackChunkdocs_next||[]).push([[92601],{45097:e=>{e.exports=JSON.parse('{"tag":{"label":"externaldns","permalink":"/docs-next/pr-preview/pr-377/docs/tags/externaldns","allTagsPath":"/docs-next/pr-preview/pr-377/docs/tags","count":3,"items":[{"id":"best-practices/containers/cloud-container-engine/automate-dns-records-creation-from-cce-ingresses-with-externaldns","title":"Automate DNS Records Creation from CCE Ingresses with ExternalDNS","description":"ExternalDNS is a Kubernetes component used to manage DNS records for services and applications running in a Kubernetes cluster. It automates the creation, update, and deletion of DNS records based on the state of resources within the cluster. ExternalDNS is typically employed in scenarios where you need to expose services running inside a Kubernetes cluster to the outside world with fully qualified domain names (FQDNs), ensuring they are accessible by external users.","permalink":"/docs-next/pr-preview/pr-377/docs/best-practices/containers/cloud-container-engine/automate-dns-records-creation-from-cce-ingresses-with-externaldns"},{"id":"best-practices/containers/cloud-container-engine/enabling-external-traffic-with-gateway-api","title":"Enabling External Traffic with Gateway API","description":"Before deploying our workloads, the CCE cluster must be equipped with a set of foundational components. In this section, we\'ll install and configure essential prerequisites such as a Gateway Controller for routing external traffic, cert-manager for managing TLS certificates, and other supporting workloads. These components establish the baseline infrastructure required to expose services securely and ensure smooth operation of the application stack within the Kubernetes environment.","permalink":"/docs-next/pr-preview/pr-377/docs/best-practices/containers/cloud-container-engine/enabling-external-traffic-with-gateway-api"},{"id":"best-practices/containers/cloud-container-engine/enabling-external-traffic-with-ingress-api","title":"Enabling External Traffic with Ingress API","description":"Before deploying our workloads, the CCE cluster must be equipped with a set of foundational components. In this section, we\'ll install and configure essential prerequisites such as an Ingress Controller for routing external traffic, cert-manager for managing TLS certificates, and other supporting workloads. These components establish the baseline infrastructure required to expose services securely and ensure smooth operation of the application stack within the Kubernetes environment.","permalink":"/docs-next/pr-preview/pr-377/docs/best-practices/containers/cloud-container-engine/enabling-external-traffic-with-ingress-api"}],"unlisted":false}}')}}]);